// Extract aircraft details from email content
const items = [];

for (const item of $input.all()) {
  const emailBody = item.json.snippet || item.json.textPlain || '';
  const subject = item.json.subject || '';
  const fullText = subject + ' ' + emailBody;

  // Common aircraft manufacturers
  const manufacturers = ['Gulfstream', 'Bombardier', 'Cessna', 'Embraer', 'Dassault', 'Boeing', 'Airbus', 'Beechcraft', 'Cirrus', 'Pilatus', 'Honda', 'Learjet', 'Citation', 'Challenger', 'Falcon', 'Global', 'Legacy'];

  // Extract manufacturer
  let manufacturer = '';
  for (const mfr of manufacturers) {
    if (fullText.includes(mfr)) {
      manufacturer = mfr;
      break;
    }
  }

  // Extract year (looking for 4-digit numbers between 1980-2025)
  const yearMatch = fullText.match(/\b(19[89]\d|20[0-2]\d)\b/);
  const year = yearMatch ? parseInt(yearMatch[0]) : null;

  // Extract price (looking for numbers with $ or million/M)
  const pricePatterns = [
    /\$([\d,]+(?:\.\d+)?)(M|million)?/gi,
    /([\d,]+(?:\.\d+)?)\s*(million|M)\s*(?:USD|dollars)?/gi
  ];

  let price = null;
  for (const pattern of pricePatterns) {
    const priceMatch = fullText.match(pattern);
    if (priceMatch) {
      const numStr = priceMatch[0].replace(/[^\d.]/g, '');
      const num = parseFloat(numStr);
      // If it says 'M' or 'million', multiply by 1,000,000
      if (priceMatch[0].toLowerCase().includes('m') || priceMatch[0].toLowerCase().includes('million')) {
        price = num * 1000000;
      } else if (num > 100000) { // Likely already in dollars
        price = num;
      } else {
        price = num * 1000000; // Assume millions if small number
      }
      break;
    }
  }

  // Determine category based on keywords and manufacturer
  let category = '';
  if (fullText.match(/heavy|G[456]50|Global|7[57]00|Falcon 7X|BBJ/i)) {
    category = 'Heavy Jet';
  } else if (fullText.match(/midsize|mid-size|Citation X|Challenger 3[0-9]{2}|G[12]80|Legacy 500/i)) {
    category = 'Midsize Jet';
  } else if (fullText.match(/light|Citation (M2|CJ|Mustang)|Learjet|Phenom/i)) {
    category = 'Light Jet';
  } else if (fullText.match(/turboprop|King Air|Pilatus|Caravan/i)) {
    category = 'Turboprop';
  } else if (fullText.match(/piston|Cirrus|SR22/i)) {
    category = 'Piston';
  }

  // Extract model (get text after manufacturer, up to year or newline)
  let model = '';
  if (manufacturer) {
    const modelMatch = fullText.match(new RegExp(manufacturer + '\\s+([A-Z0-9\\s-]+)', 'i'));
    if (modelMatch) {
      model = modelMatch[1].split(/[,\n(]/)[0].trim().substring(0, 30);
    }
  }

  items.push({
    json: {
      emailId: item.json.id,
      emailSubject: subject,
      emailSnippet: emailBody.substring(0, 200),
      emailDate: item.json.internalDate,
      manufacturer: manufacturer || 'Unknown',
      model: model || 'Unknown',
      year: year,
      price: price,
      category: category || 'Unknown',
      rawEmailBody: emailBody
    }
  });
}

return items;

// Match aircraft to leads based on criteria
const matches = [];

for (const item of $input.all()) {
  const aircraft = item.json.aircraft;
  const leads = item.json.leads;

  if (!leads || !Array.isArray(leads)) {
    continue;
  }

  for (const lead of leads) {
    let matchScore = 0;
    const matchReasons = [];

    // Category/Type match (most important)
    if (aircraft.category && lead.aircraft_type) {
      if (aircraft.category.toLowerCase() === lead.aircraft_type.toLowerCase()) {
        matchScore += 50;
        matchReasons.push(`✓ Aircraft type matches: ${aircraft.category}`);
      }
    }

    // Budget match
    if (aircraft.price && lead.budget && lead.budget_known) {
      const budgetDiff = Math.abs(aircraft.price - lead.budget);
      const budgetDiffPercent = (budgetDiff / lead.budget) * 100;

      if (budgetDiffPercent <= 10) {
        matchScore += 30;
        matchReasons.push(`✓ Price within 10% of budget: $${(aircraft.price / 1000000).toFixed(2)}M vs $${(lead.budget / 1000000).toFixed(2)}M budget`);
      } else if (budgetDiffPercent <= 20) {
        matchScore += 20;
        matchReasons.push(`✓ Price within 20% of budget: $${(aircraft.price / 1000000).toFixed(2)}M vs $${(lead.budget / 1000000).toFixed(2)}M budget`);
      } else if (aircraft.price <= lead.budget) {
        matchScore += 10;
        matchReasons.push(`○ Price under budget: $${(aircraft.price / 1000000).toFixed(2)}M (budget: $${(lead.budget / 1000000).toFixed(2)}M)`);
      }
    } else if (aircraft.price && !lead.budget_known) {
      matchScore += 5;
      matchReasons.push(`○ Budget unknown for lead, aircraft price: $${(aircraft.price / 1000000).toFixed(2)}M`);
    }

    // Year preference match
    if (aircraft.year && lead.year_preference) {
      const yearPref = lead.year_preference;
      if (yearPref.oldest && yearPref.newest) {
        if (aircraft.year >= yearPref.oldest && aircraft.year <= yearPref.newest) {
          matchScore += 20;
          matchReasons.push(`✓ Year matches preference: ${aircraft.year} (wants ${yearPref.oldest}-${yearPref.newest})`);
        } else if (aircraft.year >= yearPref.oldest - 2 && aircraft.year <= yearPref.newest + 2) {
          matchScore += 10;
          matchReasons.push(`○ Year close to preference: ${aircraft.year} (wants ${yearPref.oldest}-${yearPref.newest})`);
        }
      }
    }

    // Only include matches with score >= 50 (at minimum, type must match)
    if (matchScore >= 50) {
      matches.push({
        json: {
          matchScore: matchScore,
          lead: {
            id: lead.id,
            name: lead.name,
            company: lead.company,
            aircraft_type: lead.aircraft_type,
            budget: lead.budget,
            budget_known: lead.budget_known,
            year_preference: lead.year_preference,
            status: lead.status
          },
          aircraft: {
            manufacturer: aircraft.manufacturer,
            model: aircraft.model,
            year: aircraft.year,
            price: aircraft.price,
            category: aircraft.category,
            emailSubject: aircraft.emailSubject,
            emailSnippet: aircraft.emailSnippet,
            emailId: aircraft.emailId
          },
          matchReasons: matchReasons,
          timestamp: new Date().toISOString()
        }
      });
    }
  }
}

// Sort by match score descending
matches.sort((a, b) => b.json.matchScore - a.json.matchScore);

return matches.length > 0 ? matches : [{ json: { noMatches: true } }];

// Format matches for email notification
const allMatches = $input.all();

if (allMatches.length === 0 || allMatches[0].json.noMatches) {
  return [{ json: { noMatches: true } }];
}

let emailBody = `<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; }
    h2 { color: #2563eb; }
    .match { 
      background: #f0f9ff; 
      border-left: 4px solid #2563eb; 
      padding: 15px; 
      margin: 15px 0;
      border-radius: 4px;
    }
    .score { 
      background: #2563eb; 
      color: white; 
      padding: 4px 12px; 
      border-radius: 12px; 
      font-weight: bold;
      display: inline-block;
      margin-bottom: 10px;
    }
    .lead-info { color: #1e40af; font-weight: bold; margin: 10px 0; }
    .aircraft-info { color: #0f766e; font-weight: bold; margin: 10px 0; }
    .reasons { margin: 10px 0; }
    .reasons li { margin: 5px 0; }
    .email-link { color: #7c3aed; }
  </style>
</head>
<body>
  <h2>🎯 Aircraft-Lead Matches Found (${allMatches.length})</h2>
  <p>Generated: ${new Date().toLocaleString()}</p>
`;

let telegramText = `🎯 *Aircraft-Lead Matches Found (${allMatches.length})*\n\n`;

for (let i = 0; i < allMatches.length; i++) {
  const match = allMatches[i].json;
  const lead = match.lead;
  const aircraft = match.aircraft;

  // Email format
  emailBody += `
  <div class="match">
    <div class="score">Match Score: ${match.matchScore}/100</div>

    <div class="lead-info">
      👤 Lead: ${lead.name} ${lead.company ? `(${lead.company})` : ''}
      <br/>Type: ${lead.aircraft_type} | Budget: ${lead.budget ? '$' + (lead.budget / 1000000).toFixed(2) + 'M' : 'Not specified'} | Status: ${lead.status}
    </div>

    <div class="aircraft-info">
      ✈️ Aircraft: ${aircraft.manufacturer} ${aircraft.model} (${aircraft.year || 'Year N/A'})
      <br/>Category: ${aircraft.category} | Price: ${aircraft.price ? '$' + (aircraft.price / 1000000).toFixed(2) + 'M' : 'Price N/A'}
    </div>

    <div class="reasons">
      <strong>Match Reasons:</strong>
      <ul>
        ${match.matchReasons.map(r => `<li>${r}</li>`).join('')}
      </ul>
    </div>

    <p><strong>Email:</strong> ${aircraft.emailSubject}</p>
    <p class="email-link"><em>${aircraft.emailSnippet}...</em></p>
  </div>
  `;

  // Telegram format (simplified)
  telegramText += `*Match ${i + 1}* (Score: ${match.matchScore}/100)\n`;
  telegramText += `👤 *Lead:* ${lead.name}${lead.company ? ` (${lead.company})` : ''}\n`;
  telegramText += `   Type: ${lead.aircraft_type} | Budget: ${lead.budget ? '$' + (lead.budget / 1000000).toFixed(2) + 'M' : 'N/A'}\n`;
  telegramText += `✈️ *Aircraft:* ${aircraft.manufacturer} ${aircraft.model} (${aircraft.year || 'N/A'})\n`;
  telegramText += `   Price: ${aircraft.price ? '$' + (aircraft.price / 1000000).toFixed(2) + 'M' : 'N/A'}\n`;
  telegramText += `📧 ${aircraft.emailSubject}\n\n`;
}

emailBody += `
</body>
</html>`;

return [{
  json: {
    emailSubject: `🎯 ${allMatches.length} Aircraft-Lead Match${allMatches.length > 1 ? 'es' : ''} Found!`,
    emailBody: emailBody,
    telegramText: telegramText,
    matchCount: allMatches.length,
    matches: allMatches.map(m => m.json)
  }
}];
